var tasking_System_Settings_Scripts = Class.create();
// Tasker Knowledge Base - ships with Tasker
tasking_System_Settings_Scripts.CONST_DTECH_KNOWLEDGE_BASE_ID = "ddba8256db4d99501e1792c5d496195a";

