tasking_System_Settings_Scripts.CONST_ROLE_TEMPLATE_ADMINISTRATOR = "x_153465_discovert.tasker_process_template_admin";
tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_TEMPLATE_DESIGNER = "x_153465_discovert.tasker_process_template_global";
tasking_System_Settings_Scripts.CONST_ROLE_PERSONAL_TEMPLATE_DESIGNER = "x_153465_discovert.tasker_process_template_user";
tasking_System_Settings_Scripts.CONST_ROLE_TASKER_USER = "x_153465_discovert.tasker_user";
// STRY0129041
tasking_System_Settings_Scripts.CONST_ARRAY_ALL_GLOBAL_ROLES = ['x_153465_discovert.tasker_user', 
																'x_153465_discovert.tasker_process_template_user',
																'x_153465_discovert.Task_Executive',
