																'x_153465_discovert.tasker_process_template_global',
																'x_153465_discovert.tasker_process_template_admin',
																'x_153465_discovert.tasker_organizational_admin',
																'x_153465_discovert.tasker_application_admin',
																'admin'
																];

// SYSTEM PROPERTIES NAMES
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASKER_APPLICATION_ADMINISTRATOR_GROUP = "x_153465_discovert.role_tasker_application_administrator_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_GLOBAL_HIERARCHY_ADMINISTRATOR_GROUP = "x_153465_discovert.role_global_hierarchy_administrator_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASK_ADMINISTRATOR_GROUP = "x_153465_discovert.role_task_administrator_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASK_EXECUTIVE_GROUP = "x_153465_discovert.role_task_executive_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TEMPLATE_DESIGNER_PERMISSIONS_ADMINISTRATOR_GROUP = "x_153465_discovert.role_template_designer_permissions_administrator_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_GLOBAL_TEMPLATE_DESIGNER_GROUP = "x_153465_discovert.role_global_template_designer_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_PERSONAL_TEMPLATE_DESIGNER_GROUP = "x_153465_discovert.role_personal_template_designer_group";
tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASKER_USER_GROUP = "x_153465_discovert.role_tasker_user_group";

// SYSTEM PROPERTIES SETINGS
tasking_System_Settings_Scripts.TASK_FORM_PROPERTY_VALUE = parseInt(gs.getProperty('x_153465_discovert.restrict_task_form_view'));
tasking_System_Settings_Scripts.CONST_QUICK_TASK_FORMS_ONLY = 1;
tasking_System_Settings_Scripts.CONST_ADVANCED_TASK_FORMS_ONLY = 2;
tasking_System_Settings_Scripts.CONST_BOTH_QUICK_AND_ADVANCED_TASK_FORMS = 3;

// SYSTEM PROPERTIES VALUES
tasking_System_Settings_Scripts.CONST_USES_GROUPS_FOR_ROLES = (gs.getProperty('x_153465_discovert.uses_groups_for_roles') == 'true');
tasking_System_Settings_Scripts.CONST_ROLE_TASKER_APPLICATION_ADMINISTRATOR_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASKER_APPLICATION_ADMINISTRATOR_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_HIERARCHY_ADMINISTRATOR_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_GLOBAL_HIERARCHY_ADMINISTRATOR_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_TASK_ADMINISTRATOR_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASK_ADMINISTRATOR_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_TASK_EXECUTIVE_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASK_EXECUTIVE_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_TEMPLATE_DESIGNER_PERMISSIONS_ADMINISTRATOR_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TEMPLATE_DESIGNER_PERMISSIONS_ADMINISTRATOR_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_TEMPLATE_DESIGNER_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_GLOBAL_TEMPLATE_DESIGNER_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_PERSONAL_TEMPLATE_DESIGNER_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_PERSONAL_TEMPLATE_DESIGNER_GROUP);
tasking_System_Settings_Scripts.CONST_ROLE_TAKSER_USER_GROUP = 
	gs.getProperty(tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASKER_USER_GROUP);

tasking_System_Settings_Scripts.prototype = {

	initialize: function() {
	},

	// STRY0099280
	SUSPENSE_DEFAULT_CURRENT_LOCAL_TIME: 0,
	SUSPENSE_DEFAULT_END_OF_DAY: 1,
	SUSPENSE_DEFAULT_CUSTOM_TIME: 2,

	// STRY0136617 - check if chat is enabled for this user
	isChatEnabledForUser: function(){
		var _isChatEnabled = false;
		var _userChatEnabled = false;
		var _isCommunicationServerEnabled = gs.getProperty('com.glide.cs.collab.enabled') == 'true';
		var _isNextUIEnabled = gs.getProperty('glide.ui.polaris.experience') == 'true';
		if(_isNextUIEnabled){
			_userChatEnabled = gs.getUser().getPreference('glide.ui.polaris.use') == 'true';
		}
		_isChatEnabled = _isCommunicationServerEnabled && _isNextUIEnabled && _userChatEnabled;

		return _isChatEnabled;
	},

	// STRY0129039 - STRY0129041 - load Groups for Roles and reset when properties are saved
	loadGlobalRolesForGroupsSettings: function(){
		// if the base setting isn't defined, the object has not been loaded yet, load it
		if(g_taskRoleGroups.uses_groups_for_roles == undefined){
			var properties = {};
			properties = this.loadCategoryProperties(tasking_System_Settings_Scripts.CONST_CATEGORY_GROUP_MANAGEMENT);
			properties = this.validateAllGroups(properties);
			for (var i = 0; i < properties.length; i++) {
				var property = properties[i];		
				var objProperty = {name:"", displayValue:"",value:""};
				switch(property.name){
					case 'x_153465_discovert.uses_groups_for_roles': // skip this, may do something differnt here when category has the group filter
						g_taskRoleGroups.uses_groups_for_roles = property.value=="true" || property.value==true;
						break;
					default:
						g_taskRoleGroups[property.roleName] = property;
				}
			}
		}
		return g_taskRoleGroups;
	},

	resetGlobalRolesForGroupsSettings: function(){
		// reset the global object
		g_taskRoleGroups = {};
		// reload global object
		this.loadGlobalRolesForGroupsSettings();
	},

	_setSystemProperty: function(propertyName, propertyValue){
		// DFCT0011262 - Unable to select "Use groups for roles" button
		var grSysProperty = new GlideRecord("sys_properties");
		grSysProperty.addQuery("name", propertyName);
		grSysProperty.query();
		if(grSysProperty.next()){
			grSysProperty.setValue("value", propertyValue);
			grSysProperty.update();
		}
	},

	// STRY0124860
	saveProperties: function(properties){
		for (var i = 0; i < properties.length; i++) {
			property = properties[i];
			var propertyValue;
			if(typeof property.value == "object"){
				propertyValue = property.value.value;
			} else {
				propertyValue = property.value;
			}
			propertyValue = propertyValue + "";
			// STRY0146507 - Certification Failed Test Results - this is ONLY used during setup
			this._setSystemProperty(property.name, propertyValue);
		}
		// reload global object with updated values
		this.resetGlobalRolesForGroupsSettings();
	},

	// STRY0124860
	loadCategoryProperties: function(categoryName){
		var properties = [];
		// DFCT0011207 all TAA to update Tasker Properties
		// var gr_categoryProperties = new GlideRecordSecure("sys_properties_category_m2m");
		var gr_categoryProperties = new GlideRecord("sys_properties_category_m2m");
		var gr_Properties = new GlideRecordSecure("sys_properties");
		gr_categoryProperties.addQuery("category.name", categoryName);
		gr_categoryProperties.orderBy("order");
		gr_categoryProperties.query();
		while(gr_categoryProperties.next()){
			if(gr_Properties.get(gr_categoryProperties.getValue("property"))){
				var property = {};
				property.name = gr_Properties.getValue("name");
				property.categoryName=categoryName;
				property.suffix = gr_Properties.getValue("suffix");
				property.description = gr_Properties.getValue("description");
				var tempAdditoinalNote = gs.getMessage("Tasker - Property Additional Note for [" + property.name  + "]");
				if(!tempAdditoinalNote.startsWith("Tasker - Property Additional Note for")){
					property.additionalNote = tempAdditoinalNote;
				} else {
					property.additionalNote = '';
				}
				var tempKBArticle = gs.getMessage("Tasker - Property KB Article ID for [" + property.name  + "]");
				if(!tempKBArticle.startsWith("Tasker - Property KB Article ID for")){
					property.KBArticle = tempKBArticle;
				} else {
					property.KBArticle = '';
				}
				property.type = gr_Properties.getValue("type");
				property.choices = gr_Properties.getValue("choices");
				property.value = gr_Properties.getValue("value");
				property.originalValue=gr_Properties.getValue("value");
				property.field = {};
				properties.push(property);
			}
		}
		if(categoryName == "Groups Management"){
			properties = this._loadGroupNameValuePairs(properties);
		}
		return properties;
	},
	// STRY0124860  
	_loadGroupNameValuePairs: function(properties){
		var gr_groups = new GlideRecord("sys_user_group");
		for (var i = 0; i < properties.length; i++) {
			var property = properties[i];		
			var objProperty = {name:"", displayValue:"",value:""};
			switch(property.name){
				case 'x_153465_discovert.uses_groups_for_roles': // skip this, may do something differnt here when category has the group filter
					break;
				default:
					property.roleName = this._getRoleNameforPropertyName(property.name);
					if(property.value && property.value !=""){
						if(gr_groups.get(property.value)){
							objProperty.value = property.value;
							objProperty.displayValue = gr_groups.getDisplayValue();
							objProperty.name = property.name;
						}
					}
					// reset the property value to an object so the sn-picker will pull up the name value pair
					property.value = objProperty;					
			}
		}
		return properties;
	},
	syncAllGroupRoles:function(properties) {
		for (var i = 0; i < properties.length; i++) {
			var property = properties[i];
			if (property.name != "x_153465_discovert.uses_groups_for_roles") {
				property = this.syncGroupRole(property);
			}
		}
		return properties;
	},
	syncGroupRole: function(groupProperty){
		var groupId = "";
		var groupCount = -1;
		var roleName = "";
		var inheritRoleCount = -1;
		var explicitRoleCount = -1;
		var totalRoleCount = -1;
		var memberTableRoleCount = -1;

		// Add Group to Role
		if(groupProperty.validation.groupSelected){
			if(!groupProperty.validation.groupHasRole){
				this.addRoleToGroup(groupProperty);
			}
		}
		// if explicit role members exist move to group
		if(groupProperty.validation.groupSelected && groupProperty.validation.explicitRoleCount){
			groupId = groupProperty.value.value;
			roleName = groupProperty.roleName;
			groupProperty.usersMigratedToGroup = this._migrateRoleUsersIntoGroup(groupProperty, roleName, groupId);
		}
		this._syncTaskerMembersWithRole(groupProperty);
		return groupProperty;
	},
	syncMembersInMemberTableWithRole: function(groupProperty){
		this._syncTaskerMembersWithRole(groupProperty);
	},

	//  STRY0131148 - Members table changed to Users table, left functions and objects as they were to reduce code change
	_syncTaskerMembersWithRole: function(groupProperty){
		var uis = new UserInfoScripts();
		var roleName;
		var recordsProcessed = 0; // counts all records processed
		var usersProcessed = 0;
		var recordsChanged = 0; // records all records changed
		var usersChanged = 0;
		var usersAdded = 0;
		var userHasRole = false;
		var fieldName = "";
		//  STRY0131148 - Members table changed to Users table, left functions and objects as they were to reduce code change
		groupProperty.MemberTableSyncResults = {};
		//  STRY0131148 - updated to move table - get field for role name
		var grOrgUsers = new GlideRecordSecure('x_153465_discovert_organization_user');

		if (groupProperty.roleName && groupProperty.roleName != ""){
			roleName = groupProperty.roleName;
			fieldName = this._getFieldforRoleName(roleName);
			// go through users one at a time
			grOrgUsers.orderBy("u_tasker_user");
			grOrgUsers.query();
			while(grOrgUsers.next()){
				// DFCT0011531 - fixed issue in 2.8.1, currentUserId was not defined
				var currentUserId = grOrgUsers.getValue("u_tasker_user");
				userHasRole = uis.UserHasRoleScoped(roleName, currentUserId);
				// increment process users count
				usersProcessed++;
				recordsProcessed++;
				// check each record for the user
				if(userHasRole != grOrgUsers.getValue(fieldName)){
					// no need to update any groups or roles, changing table to match group or roles
					grOrgUsers.setWorkflow(false);
					grOrgUsers.setValue(fieldName,userHasRole);
					grOrgUsers.update("User Sycn performed by user: " + gs.getUserDisplayName() + "[ User Id: "+ gs.getUserName() + "]");
					recordsChanged++;
					usersChanged++;
				}
			}
			// DFCT0011531 - fixed issue in 2.8.1, removed property
			usersAdded =+ this._addUsersWithRoleNotInOrganizationalUsersTable(roleName, fieldName);
			usersProcessed =+ usersAdded;
			usersChanged =+ usersAdded;
			recordsProcessed =+ usersAdded;
			recordsChanged =+ usersAdded;

		} else{
			// no role name associated with the system property.  This should not happen, but handled here.
		}
		groupProperty.MemberTableSyncResults.recordsProcessed = recordsProcessed;
		groupProperty.MemberTableSyncResults.usersProcessed = usersProcessed;
		groupProperty.MemberTableSyncResults.recordsChanged = recordsChanged;
		groupProperty.MemberTableSyncResults.usersChanged = usersChanged;
	},

	// Make sure all users with the role are in the User Table
	// DFCT0011531 -fixed issue in 2.8.1, removed property, it wasn't used
	_addUsersWithRoleNotInOrganizationalUsersTable: function(roleName, fieldName){
		var grOrgUsers;
		var grRoleUsers = new GlideRecord('sys_user_has_role');
		var usersProcessed = 0;
		var usersChanged = 0;

		grRoleUsers.addQuery('role.name', roleName);
		grRoleUsers.query();
		while (grRoleUsers.next()) {
			grOrgUsers = new GlideRecordSecure('x_153465_discovert_organization_user');

			var roleUserId = grRoleUsers.getValue("user"); 
			grOrgUsers.addQuery("u_tasker_user", roleUserId);
			// add any users not in the system to the Organizational User table
			grOrgUsers.query();
			if (!grOrgUsers.next()) {
				grOrgUsers.initialize();
				grOrgUsers.u_tasker_user = roleUserId;
				grOrgUsers[fieldName] = true;
				grOrgUsers.insert();
				usersChanged++;
			}
		}
		return usersChanged;
	},


	migrateRoleUsersIntoGroup: function(groupProperty){
		var roleName = "";
		var groupId = "";
		var usersMigrated = 0;

		if (groupProperty.value && groupProperty.value.value){
			groupId = groupProperty.value.value;
		} else {
			// group not provided
			return -1;
		}
		roleName = this._getRoleNameforPropertyName(groupProperty.name);
		if(!roleName || roleName ==""){
			return -2;
		}
		usersMigrated = this._migrateRoleUsersIntoGroup(groupProperty, roleName, groupId);
		return usersMigrated;

	},

	TEST_RESET_Group_Management_Roles: function(RESET){
		if(RESET != "RESET"){
			gs.info("Tasker - Test - you must pass 'RESET' into the parameter RESET for this to execute.");
			return;
		}
		var properities;
		properties = this.loadCategoryProperties("Groups Management");
		properties = this.validateAllGroups(properties);
		this.TEST_RESET_AllGroupRoles(RESET, properties);
		this.TEST_RESET_clear_Group_Management_Properties(RESET, properties);

	},
	TEST_RESET_clear_Group_Management_Properties: function(RESET, properties){
		if(RESET != "RESET"){
			gs.info("Tasker - Test - you must pass 'RESET' into the parameter RESET for this to execute.");
			return;
		}		
		for (var i = 0; i < properties.length; i++) {
			var property = properties[i];
			if (property.name == "x_153465_discovert.uses_groups_for_roles") {
				// STRY0146507 - Certification Failed Test Results - this is ONLY used during setup
				this._setSystemProperty(property.name, false);
			} else {
				// STRY0146507 - Certification Failed Test Results - this is ONLY used during setup
				this._setSystemProperty(property.name, "");
			}
		}
	},
	TEST_RESET_AllGroupRoles:function(RESET, properties) {
		try{
			if(RESET != "RESET"){
				gs.info("Tasker - Test - you must pass 'RESET' into the parameter RESET for this to execute.");
				return;
			}		

			for (var i = 0; i < properties.length; i++) {
				var property = properties[i];
				if (property.name != "x_153465_discovert.uses_groups_for_roles") {
					this.TEST_RESET_Group(RESET, property);
				}
			}
		} catch(e){
			gs.addErrorMessage(gs.getMessage("Error resetting all groups in function [{0}] item with property name [{1}] - Error: [{3}]", ["tasking_System_Settings_Scripts.TEST_RESET_AllGroupRoles", property.name, e]));
		}			
	},

	TEST_RESET_Group: function(RESET, groupProperty){
		try{
			if(RESET != "RESET"){
				gs.info("Tasker - Test - you must pass 'RESET' into the parameter RESET for this to execute.");
				return;
			}		

			var groupId = "";
			var roleName = "";
			var groupName = "Not Selected";

			// Add Group to Role
			if(groupProperty.validation.groupSelected){
				if(groupProperty.validation.groupHasRole){
					groupName = groupProperty.value.displayValue;
					this.TEST_RESET_removeRoleFromGroup(RESET, groupProperty);
				}
			}
			roleName = groupProperty.roleName;
			// if explicit role members exist move to group
			if(groupProperty.validation.groupSelected){
				groupId = groupProperty.value.value;
				roleName = groupProperty.roleName;
				this.TEST_RESET_Only_migrateGroupUsersIntoRole(RESET, roleName, groupId);
			}
			gs.info("Tasker - Test - Role [{0}] with Group [{1}} was reset in a test script run by user[{2}].", [roleName, groupName, gs.getUserDisplayName() ]);
		} catch(e){

			gs.addErrorMessage(gs.getMessage("Error resetting group in function [{0}] unable to reset group [{1}] with role [{2}] - Error: [{3}]", 
										["tasking_System_Settings_Scripts.TEST_RESET_Group", groupId, roleName, e]));
		}							

	},

	TEST_RESET_removeRoleFromGroup: function (RESET, groupProperty){
		try{
			if(RESET != "RESET"){
				gs.info("Tasker - Test - you must pass 'RESET' into the parameter RESET for this to execute.");
				return;
			}		

			var groupId = "";
			var roleName = "";
			var roleId = "";
			var roleAdded = false;
			if(groupProperty.roleName && groupProperty.roleName != ""){
				roleName = groupProperty.roleName;
				roleId = this._getRoleIdForRoleName(roleName);
			}
			if (groupProperty.value && groupProperty.value.value){
				groupId = groupProperty.value.value;
			}
			// roleName should always be populated
			if( roleId != "" && groupId != ""){
				var grGroupRole = new GlideRecord('sys_group_has_role');
				grGroupRole.addQuery('role',roleId);
				grGroupRole.addQuery('group',groupId);
				grGroupRole.query();
				if(grGroupRole.next()){
					grGroupRole.deleteRecord();
					gs.info("Tasker - Test - Role [{0}] was removed from Group [{1}} in a test script run by user[{2}].", [roleName, grGroupRole.getDisplayValue("group"), gs.getUserDisplayName() ]);
				}
			}
		} catch(e){

			gs.addErrorMessage(gs.getMessage("Error removing group from role in function [{0}] unable to remove group [{1}] from role [{2}] - Error: [{3}]", 
											["tasking_System_Settings_Scripts.TEST_RESET_removeRoleFromGroup", groupId, roleName, e]));
		}				
	},

	TEST_RESET_Only_migrateGroupUsersIntoRole: function(RESET, roleName, groupId){
		try{
			if(RESET != "RESET"){
				gs.info("Tasker - Test - you must pass 'RESET' into the parameter RESET for this to execute.");
				return;
			}			
			var grRole = new GlideRecord('sys_user_role');
			var roleId = "";
			var grGroupMember = new GlideRecord('sys_user_grmember');
			var grRoleUsers = new GlideRecord('sys_user_has_role');
			var countUsersMigrated = 0;

			// get role name
			grRole.addQuery("name", roleName);
			grRole.query();
			if(grRole.next()){
				roleId = grRole.getUniqueValue();
			} else {
				gs.addErrorMessage(gs.getMessage("Error in test script to move group users back to role. Role Name [{0}]not found. ",[roleName]));
				return;
			}


			grGroupMember.addQuery("group", groupId);
			grGroupMember.query();
			// process group membrs
			while (grGroupMember.next()) {
				grRoleUsers.addQuery('role.name', roleName);
				grRoleUsers.addQuery('user', grGroupMember.user);
				grRoleUsers.addQuery("inherited", false);
				grRoleUsers.query();
				// if user doesn't have role explicitly, give the user the role explicitly
				if(!grRoleUsers.next()){
					grRoleUsers.initialize();
					grRoleUsers.user = grGroupMember.user;
					grRoleUsers.role = roleId;
					grRoleUsers.inherited = false;
					grRoleUsers.insert();
					gs.info("Tasker - Test - User [{0}] added explicitly to a role [{1}] in a test script run by user[{2}].", [grGroupMember.getDisplayValue("user"), roleName, gs.getUserDisplayName() ]);
				}
				// remove the user form the group as this is used for test only, we are just removing them here
				grGroupMember.deleteRecord();
				gs.info("Tasker - Test - User [{0}] was removed from group [{1}] in a test script run by user[{2}].", [grGroupMember.getDisplayValue("user"), grGroupMember.getDisplayValue("group"), gs.getUserDisplayName() ]);
				countUsersMigrated++;
			}
			gs.info("Tasker - Test - User[{0} ran a test script that migrated [{1}]].", [grGroupMember.getDisplayValue("user"), grGroupMember.getDisplayValue("group"), gs.getUserDisplayName() ]);
		} catch(e){

			gs.addErrorMessage(gs.getMessage("Error migrating users in roles into a group in function [{0}] unable to migrate users from role with name: [{1}] into group with GroupId: [{2}]  - Error: [{3}]", ["tasking_System_Settings_Scripts.TEST_RESET_Only_migrateGroupUsersIntoRole",roleName, groupId, e]));
		}	
	},

	// move all users from Role to Group
	_migrateRoleUsersIntoGroup: function(property, roleName, groupId){
		try{
			var grGroupMember = new GlideRecord('sys_user_grmember');
			var grRoleUsers = new GlideRecord('sys_user_has_role');
			var countUsersMigrated = 0;

			grRoleUsers.addQuery('role.name', roleName);
			// by checking inheritted, we will find all users with the role and we can add just those users to the group
			// this will avoid unintentionally adding users inherting the role to this group.
			// if the user lost he inheritted role, they would still be in this group and we want to avoid that
			grRoleUsers.addQuery("inherited", false);
			grRoleUsers.query();
			while (grRoleUsers.next()) {
				var roleUserId = grRoleUsers.getValue("user"); 
				grGroupMember.addQuery("group", groupId);
				grGroupMember.addQuery("user", roleUserId);
				// make sure user is not already in the group
				grGroupMember.query();
				if (!grGroupMember.next()) {
					var userAdded=false;
					userAdded = this._addUserToGroup(roleUserId, groupId);
					if(userAdded){
						countUsersMigrated++;
					}
				}
				// remove them from the direct role relationship after adding them to the group
				if(!grRoleUsers.inherited){
					grRoleUsers.deleteRecord();
					gs.info(gs.getMessage("Tasker removed a user from a role using tasker group to role sync funtion. Role Name: [{0}] User Display Name: [{1}]", [roleName,grRoleUsers.getDisplayValue("user")]));

				}
			}
			return countUsersMigrated;
		} catch(e){
// you are here on getting error handling in			
			property.error = {};
			gs.addErrorMessage(gs.getMessage("Error migrating users in roles into a group in function [{0}] unable to migrate users from role with name: [{1}] into group with GroupId: [{2}]  - Error: [{3}]", ["tasking_System_Settings_Scripts._migrateRoleUsersIntoGroup",roleName, groupId, e]));
		}	
	},

	_addUserToGroup: function(userId, groupId){
		try{
			var userAdded=false;
			var grGroupUser = new GlideRecord('sys_user_grmember');
			grGroupUser.initialize();
			grGroupUser.user = userId;
			grGroupUser.group = groupId;
			grGroupUser.insert();
			userAdded = true;
			return userAdded;
		} catch(e){
			gs.addErrorMessage(gs.getMessage("Error adding user in function [{0}] with userId: [{1}] to group with GroupId: [{2}] - Error: [{3}]", ["tasking_System_Settings_Scripts._migrateRoleUsersIntoGroup", userId, groupId, e]));
		}
	},

	addRoleToGroup: function (groupProperty){
		var groupId = "";
		var roleName = "";
		var roleId = "";
		var roleAdded = false;
		if(groupProperty.roleName && groupProperty.roleName != ""){
			roleName = groupProperty.roleName;
			roleId = this._getRoleIdForRoleName(roleName);
		}
		if (groupProperty.value && groupProperty.value.value){
			groupId = groupProperty.value.value;
		}
		// roleName should always be populated
		if( roleId != "" && groupId != ""){
			var grGroupRole = new GlideRecord('sys_group_has_role');
			grGroupRole.initialize();

			grGroupRole.role = roleId;
			grGroupRole.group = groupId;
			grGroupRole.insert();
			roleAdded = true;
		}
		return roleAdded;
	},

	_getRoleIdForRoleName: function (roleName){
		var roleId = "";
		var grRole = new GlideRecord("sys_user_role");
		grRole.addQuery("name", roleName);
		grRole.query();
		if(grRole.next()){
			roleId = grRole.getUniqueValue();
		}
		return roleId;
	},

	validateAllGroups: function(properties){
		for (var i = 0; i < properties.length; i++) {
			var property = properties[i];
			if (property.name != "x_153465_discovert.uses_groups_for_roles") {
				property = this.validateGroupRole(property);
				properties[i]=property;
			}
		}
		return properties;
	},

	validateGroupRole: function(groupProperty){
		var groupId = "";
		var groupCount = -1;
		var roleName = "";
		var inheritRoleCount = -1;
		var explicitRoleCount = -1;
		var totalRoleCount = -1;
		var memberTableRoleCount = -1;

		groupProperty.validation = {};
		groupProperty.validation.validated = false;

		if(groupProperty.roleName && groupProperty.roleName != ""){
			roleName = groupProperty.roleName;
		}
		if (groupProperty.value && groupProperty.value.value){
			groupId = groupProperty.value.value;
			groupProperty.validation.groupSelected=true;
		}

		// roleName should always be populated
		if( roleName != "" && groupId != ""){
			var grGroupRole = new GlideRecord('sys_group_has_role');
			grGroupRole.addQuery('role.name', roleName);
			grGroupRole.addQuery('group', groupId);
			grGroupRole.query();
			// - check if group has role
			if (grGroupRole.next()) {
				groupProperty.validation.groupHasRole=true;
			}
		}
		// - count members in group
		if (groupId != ""){
			groupCount  = this._countGroupMembers(groupId);
		}
		groupProperty.validation.groupMemberCount = groupCount;

		// - count members in role
		if (groupProperty.roleName && groupProperty.roleName != ""){
			roleName = groupProperty.roleName;
			inheritRoleCount  = this._countRoleMembers(roleName, true);
			explicitRoleCount = this._countRoleMembers(roleName, false);
			totalRoleCount = explicitRoleCount + inheritRoleCount;
			memberTableRoleCount = this._countTaskerMembersWithRole(groupProperty, roleName);
		}

		groupProperty.validation.inheritRoleCount = inheritRoleCount;
		groupProperty.validation.explicitRoleCount = explicitRoleCount;
		groupProperty.validation.roleMemberTableRoleCount = memberTableRoleCount;

		if(groupProperty.validation.groupHasRole==true && 
			totalRoleCount <= groupCount && 
			totalRoleCount == memberTableRoleCount){
			groupProperty.validation.validated = true;
		}

		return groupProperty;
	},

	_countRoleMembers: function(roleName, inherits) {
		var count = -1; // default to error state since 0 is a valid count
		var gaRoleCount = new GlideAggregate('sys_user_has_role');
		gaRoleCount.addQuery('role.name', roleName);
		gaRoleCount.addQuery('inherited', inherits);

		gaRoleCount.addAggregate('COUNT');
		gaRoleCount.query();
		if (gaRoleCount.next()) {
			count = gaRoleCount.getAggregate('COUNT');
		}
		return count;
	},

	_countGroupMembers: function(groupId) {
		var count = -1; // default to error state since 0 is a valid count
		var gaMemberCount = new GlideAggregate('sys_user_grmember');
		gaMemberCount.addQuery('group', groupId);
		gaMemberCount.addAggregate('COUNT');
		gaMemberCount.query();

		if (gaMemberCount.next()) {
			count = gaMemberCount.getAggregate('COUNT');
		}
		return count;
	},

	//  STRY0131148 - Members table changed to Users table, left functions and objects as they were to reduce code change
	_countTaskerMembersWithRole: function(groupProperty, roleName){
		var count = -1; // default to error state since 0 is a valid count
		var fieldName = "";
		// STRY0131148 - member table moved to user table for personal permissions get field for role name
		var gaOrgUsers = new GlideAggregate('x_153465_discovert_organization_user');

		fieldName = this._getFieldforRoleName(roleName);
		// Group Management - add field name to property so client doesn't have to post back to server to get it
		groupProperty.memberTableFieldName = fieldName;

		if(fieldName && fieldName!=""){
			gaOrgUsers.addQuery(fieldName, true);
		}
		// STRY0131148 - member table moved to user table for personal permissions get field for role name
		// DFCT0011531 - removed .sys_id so empty is counted
		gaOrgUsers.addAggregate('COUNT(DISTINCT', 'u_tasker_user');
		gaOrgUsers.setGroup(false);
		gaOrgUsers.query();
		if(gaOrgUsers.next()){
			// DFCT0011531 - removed .sys_id so empty is counted
			count = gaOrgUsers.getAggregate('COUNT(DISTINCT', 'u_tasker_user');
		}
		return count;
	},

	_getFieldforRoleName: function(roleName){
		var fieldName;
		switch(roleName){
			case tasking_System_Settings_Scripts.CONST_ROLE_TASKER_APPLICATION_ADMINISTRATOR:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "is_tasker_application_administrator";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_HIERARCHY_ADMINISTRATOR:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "is_global_hierarchy_administrator";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_TASK_ADMINISTRATOR:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "is_task_administrator";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_TASK_EXECUTIVE:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "is_task_executive";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_TEMPLATE_ADMINISTRATOR:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "can_manage_template_permissions";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_TEMPLATE_DESIGNER:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "can_manage_global_template";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_PERSONAL_TEMPLATE_DESIGNER:
				// STRY0131148 - moved the table for personal permissions and changed names 
				fieldName = "has_personal_template_rights";
				break;
			case tasking_System_Settings_Scripts.CONST_ROLE_TASKER_USER:
				// tasker user is not in the user table.  if the field is blank return a search for all unique members and bipass the where clause
				fieldName = "";
				break;
		}		
		return fieldName;
	},

	_getRoleNameforPropertyName: function(propertyName){
		var roleName;

		switch(propertyName){
			case tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TASKER_APPLICATION_ADMINISTRATOR_GROUP:
