			case tasking_System_Settings_Scripts.CONST_PROPERTY_NAME_ROLE_TEMPLATE_DESIGNER_PERMISSIONS_ADMINISTRATOR_GROUP:
				roleName = tasking_System_Settings_Scripts.CONST_ROLE_TEMPLATE_ADMINISTRATOR;
