	// DFCT0012183 - used the descendants and needed to create ancestors
	// returns a list of OUs where the logged-in user is a task manager plus OUs which are ancestors of the task manager OUs
	_getOUsAndAncestors: function(user, taskManagersOnly) {
		var au = new global.ArrayUtil();
		var OrgScripts = new OrganizationalScripts();
		var offices = [];
		var strOfficesAndAncestors = "";
		var officesAndAncestors = [];
		var grMemberOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		if(taskManagersOnly){
			grMemberOUs.addQuery('office_task_authority', 'true');
		}
		grMemberOUs.addQuery('office_member', user);
		grMemberOUs.query();
		while(grMemberOUs.next()){
			// DFCT0012237 - modified to reduce queries
			var OU = grMemberOUs.getValue('discover_office_hierarchy') + "";
			// add the user's office to the list
			// DFCT0012259 - DFCT0012260
			strOfficesAndAncestors = strOfficesAndAncestors==""?OU:","+OU;
			var strOfficeAncestorList = grMemberOUs.discover_office_hierarchy.u_all_ancestors_organizations;
			if(strOfficeAncestorList && strOfficeAncestorList!=""){
				// DFCT0012259 - DFCT0012260
				strOfficesAndAncestors = strOfficesAndAncestors + "," + strOfficeAncestorList;
			}
		}
		// DFCT0012259 - DFCT0012260
		officesAndAncestors = strOfficesAndAncestors.split(",");
		if (officesAndAncestors.length > 0){
			officesAndAncestors = au.unique(officesAndAncestors);
		}
		return officesAndAncestors;  
	},


	// returns a list of OUs where the logged-in user is a task manager plus OUs which are descendents of the task manager OUs - if level is 1 then only the immediate suboffices will be returned
	getTaskManagerOUsAndDescendents: function(user, level) {
		var officesAndDescendents = this._getOUsAndDescendents(user, level, true);
		return officesAndDescendents;  
	},

	// STRY0141844 - new function for new dynamic filters set up for Who can run, but useable in other ways
	// returns a list of OUs where the logged-in user is a member plus OUs which are descendents of the task manager OUs - if level is 1 then only the immediate suboffices will be returned
	getMyOUsAndDescendents: function(user, level) {
		var officesAndDescendents = this._getOUsAndDescendents(user, level, false);
		return officesAndDescendents;  
	},

	_getOUsAndDescendents: function (user, level, taskManagersOnly){
		var offices = [];
		var officesAndDescendents = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		if(taskManagersOnly){
			grOUs.addQuery('office_task_authority', 'true');
		}

		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){
			var OU = grOUs.getValue('discover_office_hierarchy');
			offices.push(OU);
			officesAndDescendents.push(OU);
		}
		for (i=0; i<offices.length; i++) {
			// Get Descendents and add them to the siblings for each OU where I am a task Manager
			officesAndDescendents = this.getDescendents(offices[i], officesAndDescendents, level);
		}
		if (officesAndDescendents.length > 0){
			var au = new global.ArrayUtil();
			officesAndDescendents = au.unique(officesAndDescendents);
		}
		return officesAndDescendents;  
	},

	// DFCT0012237 - new function to use top ous instead of all ous
	getMyOrgStructureTopOUs: function(user, onlyTaskManagers){
		var au = new global.ArrayUtil();
		var topOU;
		var topOUs = [];
		var grMemberOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMemberOUs.addQuery('office_member', user);
		if(onlyTaskManagers){
			grMemberOUs.addQuery('office_task_authority', 'true');
		}
		grMemberOUs.query();
		while(grMemberOUs.next()){
			topOU = grMemberOUs.discover_office_hierarchy.u_top_ou;
			topOUs.push(topOU);
		}
		// reduce to unique top offices
		if (topOUs.length > 0){
			au = new global.ArrayUtil();
			topOUs = au.unique(topOUs);
		}
		return topOUs;
	},

