	},

		// DFCT0012237
	_getMyTaskManagersOrgStructureOUs: function(user, onlyTaskManagers) {
		var offices = [];
		// DFCT0012237
		var topOUs = this.getMyOrgStructureTopOUs(user, onlyTaskManagers);
		var strTopOUs = topOUs.join(",");
		var ouQuery = "u_top_ouIN" + strTopOUs;	
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		grOUs.addEncodedQuery(ouQuery);
		grOUs.query();
		while(grOUs.next()){
			offices.push(grOUs.getUniqueValue());
		}		
		return offices;

	},

	getAllRelatvieOUs: function(userOffices){
		// userOffices is an array of sys_id strings
		var offices = [];
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		for (i=0; i<userOffices.length; i++) {
			if(grOU.get(userOffices[i])){
				// push parent onto offices
				if(!grOU.parent.nil()){
					var parentId = grOU.getValue('parent');
					offices.push(parentId);

					// Get siblings
					var grSiblings = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
					grSiblings.addQuery('parent', parentId);
					grSiblings.query();
					while(grSiblings.next()){
						offices.push(grSiblings.getValue('sys_id'));    
					}
				}
				// Get Descendents and add them to the siblings for each OU where I am a task Manager
				offices = this.getDescendents(userOffices[i], offices);
			}
		}
		// DFCT0010835  - add the offices received back to the array
		offices = offices.concat(userOffices);
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;
	},

	//returns OUs downstream from the specified OU
	getDescendents: function(ou, offices, level){
		var grDescendents = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		if (level == 1){
			grDescendents.addQuery('parent', ou);
		} else {
			// DFCT0012237 - removed recursion by using the ancestor list as a way to find all records where an OU is an ancestore
			grDescendents.addQuery('u_all_ancestors_organizations', 'CONTAINS', ou);
		}
		grDescendents.query();
		while(grDescendents.next()){
			offices.push(grDescendents.getValue('sys_id'));
			// DFCT0012237 - removed recursion - see above
		}
		return offices;
	},

	// ous can be one or an array
	retrieveMembersInOus: function(ous){
		var members = [];
		for (i=0; i<ous.length; i++) {
			var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
			//grOUs.addQuery('discover_office_hierarchy', 'IN', ous);
			grOUs.addQuery('discover_office_hierarchy', ous[i]);
			grOUs.query();
			while(grOUs.next()){
				members.push(grOUs.getValue('office_member'));
			}
		}
		if (members.length > 0){
			var au = new global.ArrayUtil();
			members = au.unique(members);
		}
		return members;
	},

	type: 'tasking_System_Settings_Scripts'
};
